_TerroirAvatar.vertexProgram:
varying vec2 Texcoord;
varying vec3 normal;

uniform int Time;
uniform float fps;

void main( void )
{
    float time = (float(Time)/1000.0)*fps;
    Texcoord.x = gl_MultiTexCoord0.x;
    Texcoord.y = gl_MultiTexCoord0.y;

    gl_Position = ftransform();	
    gl_ClipVertex = gl_ModelViewMatrix*gl_Vertex;
}

_TerroirAvatar.fragmentProgram:

varying vec2 Texcoord;
varying vec3 normal;

uniform int Time;
uniform int bumpsPerSplotch;

// the variables from the SplotchAvatar plugin
uniform sampler2D texture1;
uniform sampler2D texture2;
uniform sampler2D texture3;
uniform sampler2D texture4;

uniform int numSplotches;
uniform vec3 splotchPositions[4];
uniform float splotchRadius;

void main( void )
{
    vec4 color = vec4(1.0, 1.0, 1.0, 1.0); // default: white

    for (int i = 0; i < numSplotches; ++i)
    {
        // circle shape
        float dx = Texcoord.x - splotchPositions[i].x;
        float dy = Texcoord.y - splotchPositions[i].y;
        float angle = atan(dy, dx); // Angle around the splotch center
        float dist = sqrt(dx*dx + dy*dy);

        // add sine wave border to create splotches
        float amplitude = 0.2 * splotchRadius; 
        float frequency = float(bumpsPerSplotch);  
        float splotchEdge = splotchRadius + amplitude * sin(frequency * angle);

        if (dist < splotchEdge)
        {
            int type = int(splotchPositions[i].z);
            if (type == 0)
                color = texture2D(texture1, Texcoord);
            else if (type == 1)
                color = texture2D(texture2, Texcoord);
            else if (type == 2)
                color = texture2D(texture3, Texcoord);
            else if (type == 3)
                color = texture2D(texture4, Texcoord);
            break;
        }
    }
        gl_FragColor = color;
}
